content:
{
  "sentences": [
    {
      "text": "你什麼時候有空？我們可以一起去喝咖啡。",
      "pinyin": "Nǐ shénme shíhou yǒu kòng? Wǒmen kěyǐ yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "ni3 shen2me shi2hou you3 kong4? wo3men ke3yi3 yi1qi3 qu4 he1 ka1fei1.",
      "translation_en": "When are you free? We can go drink coffee together.",
      "translation_ko": "언제 시간 돼요? 같이 커피 마시러 갈 수 있어요."
    },
    {
      "text": "我們什麼時候見面？我想跟你一起看電影。",
      "pinyin": "Wǒmen shénme shíhou jiànmiàn? Wǒ xiǎng gēn nǐ yīqǐ kàn diànyǐng.",
      "pinyin_numeric": "wo3men shen2me shi2hou jian4mian4? wo3 xiang3 gen1 ni3 yi1qi3 kan4 dian4ying3.",
      "translation_en": "When shall we meet? I want to watch a movie with you.",
      "translation_ko": "우리 언제 만날까요? 당신과 같이 영화 보고 싶어요."
    },
    {
      "title": "planning to meet someone",
      "unit": "Making Plans",
      "text": "你什麼時候要吃飯？我們可以約在餐廳門口碰面。",
      "pinyin": "Nǐ shénme shíhou yào chīfàn? Wǒmen kěyǐ yuē zài cāntīng ménkǒu pèngmiàn.",
      "pinyin_numeric": "ni3 shen2me shi2hou yao4 chi1fan4? wo3men ke3yi3 yue1 zai4 can1ting1 men2kou3 peng4mian4.",
      "translation_en": "When do you want to eat? We can arrange to meet at the restaurant entrance.",
      "translation_ko": "언제 밥 먹을래요? 식당 입구에서 만나기로 할 수 있어요."
    },
    {
      "text": "他什麼時候下班？我們打算一起去逛街。",
      "pinyin": "Tā shénme shíhou xiàbān? Wǒmen dǎsuàn yīqǐ qù guàngjiē.",
      "pinyin_numeric": "ta1 shen2me shi2hou xia4ban1? wo3men da3suan4 yi1qi3 qu4 guang4jie1.",
      "translation_en": "When does he get off work? We plan to go shopping together.",
      "translation_ko": "그는 언제 퇴근해요? 우리 같이 쇼핑하러 갈 계획이에요."
    },
    {
      "text": "你什麼時候要見朋友？我們可以一起去喝咖啡聊天。",
      "pinyin": "Nǐ shénme shíhou yào jiàn péngyou? Wǒmen kěyǐ yīqǐ qù hē kāfēi liáotiān.",
      "pinyin_numeric": "ni3 shen2me shi2hou yao4 jian4 peng2you? wo3men ke3yi3 yi1qi3 qu4 he1 ka1fei1 liao2tian1.",
      "translation_en": "When are you meeting a friend? We can go drink coffee and chat together.",
      "translation_ko": "언제 친구를 만날 거예요? 같이 커피 마시면서 이야기할 수 있어요."
    },
    {
      "text": "我們什麼時候約時間？我想跟你一起去看電影。",
      "pinyin": "Wǒmen shénme shíhou yuē shíjiān? Wǒ xiǎng gēn nǐ yīqǐ qù kàn diànyǐng.",
      "pinyin_numeric": "wo3men shen2me shi2hou yue1 shi2jian1? wo3 xiang3 gen1 ni3 yi1qi3 qu4 kan4 dian4ying3.",
      "translation_en": "When shall we set a time? I want to go watch a movie with you.",
      "translation_ko": "우리 언제 시간을 정할까요? 당신과 같이 영화 보러 가고 싶어요."
    },
    {
      "text": "你什麼時候要取消約會？我們可以改天再見面。",
      "pinyin": "Nǐ shénme shíhou yào qǔxiāo yuēhuì? Wǒmen kěyǐ gǎitiān zài jiànmiàn.",
      "pinyin_numeric": "ni3 shen2me shi2hou yao4 qu3xiao1 yue1hui4? wo3men ke3yi3 gai3tian1 zai4 jian4mian4.",
      "translation_en": "When do you want to cancel the date? We can meet another day.",
      "translation_ko": "언제 약속을 취소할 거예요? 우리 다른 날 다시 만날 수 있어요."
    },
    {
      "text": "她什麼時候要提早到？我們可以在咖啡店等她。",
      "pinyin": "Tā shénme shíhou yào tízǎo dào? Wǒmen kěyǐ zài kāfēi diàn děng tā.",
      "pinyin_numeric": "ta1 shen2me shi2hou yao4 ti2zao3 dao4? wo3men ke3yi3 zai4 ka1fei1 dian4 deng3 ta1.",
      "translation_en": "When does she want to arrive early? We can wait for her at the coffee shop.",
      "translation_ko": "그녀는 언제 일찍 도착할 거예요? 우리 커피숍에서 그녀를 기다릴 수 있어요."
    },
    {
      "text": "你什麼時候要延後約會？我們可以下次再約。",
      "pinyin": "Nǐ shénme shíhou yào yánhòu yuēhuì? Wǒmen kěyǐ xiàcì zài yuē.",
      "pinyin_numeric": "ni3 shen2me shi2hou yao4 yan2hou4 yue1hui4? wo3men ke3yi3 xia4ci4 zai4 yue1.",
      "translation_en": "When do you want to postpone the date? We can arrange it next time.",
      "translation_ko": "언제 약속을 연기할 거예요? 우리 다음에 다시 약속할 수 있어요."
    },
    {
      "text": "我們什麼時候要碰面？你可以在捷運站等我。",
      "pinyin": "Wǒmen shénme shíhou yào pèngmiàn? Nǐ kěyǐ zài jiéyùn zhàn děng wǒ.",
      "pinyin_numeric": "wo3men shen2me shi2hou yao4 peng4mian4? ni3 ke3yi3 zai4 jie2yun4 zhan4 deng3 wo3.",
      "translation_en": "When shall we meet? You can wait for me at the MRT station.",
      "translation_ko": "우리 언제 만날까요? 지하철역에서 저를 기다리셔도 돼요."
    }
  ]
}
